class a{constructor(e){if(this.element=typeof e=="string"?document.querySelector(e):e,!this.element){console.warn("MoneyInput: Elemento não encontrado");return}this.init()}init(){this.element.addEventListener("input",e=>this.handleInput(e)),this.element.addEventListener("blur",e=>this.handleBlur(e)),this.element.addEventListener("focus",e=>this.handleFocus(e)),this.element.value&&(this.element.value=this.format(this.element.value))}handleInput(e){const t=e.target.selectionStart,n=e.target.value.length;e.target.value=this.format(e.target.value);const r=e.target.value.length-n;e.target.setSelectionRange(t+r,t+r)}handleBlur(e){e.target.value&&(e.target.value=this.format(e.target.value))}handleFocus(e){setTimeout(()=>e.target.select(),0)}format(e){let t=e.replace(/\D/g,"");if(!t)return"";let n=parseInt(t,10);return n>99999999999&&(n=99999999999),(n/100).toLocaleString("pt-BR",{style:"currency",currency:"BRL"})}getValue(){const e=this.element.value;if(!e)return 0;const t=e.replace("R$","").replace(/\./g,"").replace(",",".").trim();return parseFloat(t)||0}setValue(e){typeof e=="number"&&(this.element.value=this.format(String(Math.round(e*100))))}static applyToAll(e=".money-mask"){const t=document.querySelectorAll(e);return Array.from(t).map(n=>new a(n))}}export{a as MoneyInput};
